  (function() {
    var html = '<!-- 多环境配置（从 magic-login.html 拆分） -->\n<div class="section-block">\n  <div class="section-title">\n    <div class="section-title-icon">\n      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n        <circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9c.26.604.852.997 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>\n      </svg>\n    </div>\n    多环境配置\n  </div>\n\n  <div class="feature-card">\n    <h4>环境划分</h4>\n    <p>根据微信小程序的 <code>__wxConfig.envVersion</code> 自动切换后端地址：</p>\n    <table class="info-table">\n      <thead><tr><th>环境</th><th>API 地址</th><th>CDN 地址</th></tr></thead>\n      <tbody>\n        <tr><td><span class="status-tag orange">develop</span></td><td><code>http://lumi.local.com/mpapi</code></td><td><code>cdn.lixiaoqian.com</code></td></tr>\n        <tr><td><span class="status-tag blue">trial</span></td><td><code>https://test-magic-space.lixiaoqian.com/mpapi</code></td><td><code>cdn.lixiaoqian.com</code></td></tr>\n        <tr><td><span class="status-tag green">release</span></td><td><code>https://magic-space.lixiaoqian.com/mpapi</code></td><td><code>develop.lixiaoqian.com</code></td></tr>\n      </tbody>\n    </table>\n  </div>\n\n  <div class="feature-card">\n    <h4>文件上传/下载</h4>\n    <p>文件操作也统一携带 Token 和门店 ID：</p>\n    <ul class="detail-list" style="margin-top:8px;">\n      <li><strong>上传</strong>（<code>wxFileUpload</code>）：通过 <code>wx.uploadFile</code> 上传，路径为 <code>baseUrl + /mz-admin/{url}</code></li>\n      <li><strong>下载</strong>（<code>wxFileDownload</code>）：通过 <code>wx.downloadFile</code> 下载，支持完整 URL 或相对路径</li>\n      <li>下载后默认通过 <code>wx.shareFileMessage</code> 以文件消息分享</li>\n    </ul>\n  </div>\n</div>';
    var div = document.createElement('div');
    div.innerHTML = html;
    var sections = div.querySelectorAll('.section-block');
    sections.forEach(function(sec) { container.appendChild(sec); });
  })();

  // --- magic-login-storage.html ---
  (function() {
    var html = '<!-- 本地存储体系（从 magic-login.html 拆分） -->\n<div class="section-block">\n  <div class="section-title">\n    <div class="section-title-icon">\n      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n        <ellipse cx="12" cy="5" rx="9" ry="3"/><path d="M21 12c0 1.66-4 3-9 3s-9-1.34-9-3"/><path d="M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5"/>\n      </svg>\n    </div>\n    本地存储体系\n  </div>\n\n  <div class="feature-card">\n    <h4>存储工具函数（storage.js）</h4>\n    <p>基于 <code>wx.setStorageSync / getStorageSync</code> 封装，提供以下功能：</p>\n    <table class="info-table">\n      <thead><tr><th>函数</th><th>说明</th></tr></thead>\n      <tbody>\n        <tr><td><code>setItem(key, value)</code></td><td>存储数据，对象/数组自动 JSON 序列化</td></tr>\n        <tr><td><code>getItem(key)</code></td><td>读取数据，自动尝试 JSON 反序列化（仅对合法 JSON 字符串）</td></tr>\n        <tr><td><code>removeItem(key)</code></td><td>删除指定 key</td></tr>\n        <tr><td><code>removeAllItem()</code></td><td>清空所有本地缓存</td></tr>\n        <tr><td><code>setItemInExpire(key, value, {expire})</code></td><td>带过期时间的存储，默认 7 天</td></tr>\n        <tr><td><code>getItemInExpire(key)</code></td><td>读取带过期时间的存储，过期自动删除</td></tr>\n      </tbody>\n    </table>\n  </div>\n\n  <div class="feature-card">\n    <h4>核心存储 Key 清单</h4>\n    <table class="info-table">\n      <thead><tr><th>Key</th><th>类型</th><th>用途</th></tr></thead>\n      <tbody>\n        <tr><td><code>access_token</code></td><td>String</td><td>正式 Token（API 鉴权）</td></tr>\n        <tr><td><code>tem_token</code></td><td>String</td><td>临时 Token（登录页使用）</td></tr>\n        <tr><td><code>expire_at</code></td><td>String</td><td>Token 过期时间</td></tr>\n        <tr><td><code>user_info</code></td><td>Object</td><td>用户资料（ID/头像/昵称/手机号/是否新用户）</td></tr>\n        <tr><td><code>user_login</code></td><td>Boolean</td><td>用户是否已主动登录</td></tr>\n        <tr><td><code>user_type</code></td><td>String</td><td>用户角色类型</td></tr>\n        <tr><td><code>currentStoreId</code></td><td>Number</td><td>当前选中的门店 ID</td></tr>\n        <tr><td><code>placeLists</code></td><td>Array</td><td>门店列表</td></tr>\n        <tr><td><code>service_phone</code></td><td>String</td><td>客服电话</td></tr>\n        <tr><td><code>super_man</code></td><td>Boolean</td><td>是否超级管理员</td></tr>\n        <tr><td><code>store_staff</code></td><td>Array</td><td>门店员工角色</td></tr>\n      </tbody>\n    </table>\n  </div>\n</div>';
    var div = document.createElement('div');
    div.innerHTML = html;
    var sections = div.querySelectorAll('.section-block');
    sections.forEach(function(sec) { container.appendChild(sec); });
  })();

  // --- magic-login-guard.html ---
  (function() {
    var html = '<!-- 登录态判断与页面守卫（从 magic-login.html 拆分） -->\n<div class="section-block">\n  <div class="section-title">\n    <div class="section-title-icon">\n      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n        <path d="M9 12l2 2 4-4"/><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>\n      </svg>\n    </div>\n    登录态判断与页面守卫\n  </div>\n\n  <!-- 手机号授权弹窗（新用户） -->\n  <div class="ui-demo-row">\n    <div class="ui-demo-item">\n      <div class="phone-wireframe"><div class="phone-notch"></div><div class="phone-screen" style="min-height:540px">\n        <div class="phone-bar"><span>9:41</span><div class="phone-bar-r"><i></i><i></i><i></i></div></div>\n        <!-- 首页背景内容（灰色） -->\n        <div style="padding:0 6px;opacity:0.2">\n          <div style="display:flex;align-items:center;gap:4px;padding:6px 10px;background:rgba(255,255,255,.8);border-radius:16px;width:fit-content">\n            <div style="width:8px;height:8px;background:#1890ff;border-radius:50%"></div>\n            <span style="font-size:8px;color:#333">魔法学院·朝阳店</span>\n          </div>\n          <div style="height:100px;background:linear-gradient(135deg,#5B21B6,#7C3AED);border-radius:8px;margin-top:6px"></div>\n          <div style="display:flex;gap:6px;margin-top:8px">\n            <div style="flex:1;height:35px;background:#E8F4FF;border-radius:8px"></div>\n            <div style="flex:1;height:35px;background:#FFF4E8;border-radius:8px"></div>\n          </div>\n          <div style="margin-top:8px;padding:10px;background:rgba(255,255,255,.06);border-radius:8px">\n            <div style="height:8px;width:50%;background:rgba(255,255,255,.08);border-radius:4px"></div>\n          </div>\n        </div>\n        <!-- 全屏遮罩 + 底部授权按钮 -->\n        <div style="position:relative;margin-top:4px">\n          <div style="position:absolute;inset:0;background:rgba(0,0,0,.55);border-radius:4px"></div>\n          <div style="position:relative;z-index:5;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:340px">\n            <!-- 协议勾选 -->\n            <div style="display:flex;align-items:center;gap:6px;margin-bottom:16px;border:2px solid #EF4444;border-radius:4px;padding:4px 8px;position:relative">\n              <span style="position:absolute;top:-8px;left:8px;background:#EF4444;color:#fff;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:600">phone-btn 组件</span>\n              <div style="width:14px;height:14px;border:1px solid rgba(255,255,255,.4);border-radius:50%;flex-shrink:0"></div>\n              <div style="font-size:7px;color:rgba(255,255,255,.6)">我已阅读并同意<span style="color:#51C6FF">《服务条款》</span>和<span style="color:#51C6FF">《隐私政策》</span></div>\n            </div>\n            <!-- 蓝色按钮：手机号快捷登录 -->\n            <div style="width:70%;padding:12px 0;background:#1890ff;border-radius:24px;text-align:center;font-size:10px;color:#fff;font-weight:600;margin-bottom:16px">手机号快捷登录</div>\n            <!-- 取消登录 -->\n            <div style="font-size:8px;color:rgba(255,255,255,.7);text-shadow:0 0 4rpx rgba(255,255,255,.3)">取消登录</div>\n          </div>\n        </div>\n      </div></div>\n      <div class="ui-desc">\n        <h5>📱 手机号授权（新用户）</h5>\n        <p>未登录用户执行需要身份的操作时，弹出 <code>phone-btn</code> 组件。新用户（<code>is_new = true</code> 或 <code>phone == \'\'</code>）显示「手机号快捷登录」蓝色按钮。</p>\n        <ul>\n          <li>全屏半透明遮罩，按钮从底部滑入（<code>bottom: 550rpx</code>）</li>\n          <li>按钮使用 <code>open-type="getPhoneNumber"</code>，微信自动拉起手机号授权</li>\n          <li>授权成功：调用 <code>/mz/updatePhone</code> 解密绑定，更新 <code>user_info</code></li>\n          <li>协议未勾选时，按钮上方覆盖一层透明拦截（<code>.hide-login</code>），点击提示先同意协议</li>\n          <li>「取消登录」关闭弹窗</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- 微信快捷登录（老用户） -->\n  <div class="ui-demo-row">\n    <div class="ui-demo-item">\n      <div class="phone-wireframe"><div class="phone-notch"></div><div class="phone-screen" style="min-height:540px">\n        <div class="phone-bar"><span>9:41</span><div class="phone-bar-r"><i></i><i></i><i></i></div></div>\n        <div style="padding:0 6px;opacity:0.2">\n          <div style="display:flex;align-items:center;gap:4px;padding:6px 10px;background:rgba(255,255,255,.8);border-radius:16px;width:fit-content">\n            <div style="width:8px;height:8px;background:#1890ff;border-radius:50%"></div>\n            <span style="font-size:8px;color:#333">魔法学院·朝阳店</span>\n          </div>\n          <div style="height:100px;background:linear-gradient(135deg,#5B21B6,#7C3AED);border-radius:8px;margin-top:6px"></div>\n          <div style="display:flex;gap:6px;margin-top:8px">\n            <div style="flex:1;height:35px;background:#E8F4FF;border-radius:8px"></div>\n            <div style="flex:1;height:35px;background:#FFF4E8;border-radius:8px"></div>\n          </div>\n        </div>\n        <div style="position:relative;margin-top:4px">\n          <div style="position:absolute;inset:0;background:rgba(0,0,0,.55);border-radius:4px"></div>\n          <div style="position:relative;z-index:5;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:340px">\n            <div style="display:flex;align-items:center;gap:6px;margin-bottom:16px">\n              <div style="width:14px;height:14px;border-radius:50%;flex-shrink:0;background:#6366F1;display:flex;align-items:center;justify-content:center;font-size:8px;color:#fff">✓</div>\n              <div style="font-size:7px;color:rgba(255,255,255,.6)">我已阅读并同意<span style="color:#51C6FF">《服务条款》</span>和<span style="color:#51C6FF">《隐私政策》</span></div>\n            </div>\n            <div style="width:70%;padding:12px 0;background:#1890ff;border-radius:24px;text-align:center;font-size:10px;color:#fff;font-weight:600;margin-bottom:16px">微信快捷登录</div>\n            <div style="font-size:8px;color:rgba(255,255,255,.7)">取消登录</div>\n          </div>\n        </div>\n      </div></div>\n      <div class="ui-desc">\n        <h5>🔑 微信快捷登录（老用户）</h5>\n        <p>已有手机号的老用户（<code>is_new = false</code> 且 <code>phone != \'\'</code>），按钮文案变为「微信快捷登录」，点击直接跳转首页，无需再次授权手机号。</p>\n        <ul>\n          <li>点击后执行 <code>handleToIndex</code>：将 <code>tem_token</code> 转存为 <code>access_token</code></li>\n          <li>标记 <code>user_login = true</code></li>\n          <li><code>reLaunch</code> 跳转首页</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- 地址不一致弹窗 -->\n  <div class="ui-demo-row">\n    <div class="ui-demo-item">\n      <div class="phone-wireframe"><div class="phone-notch"></div><div class="phone-screen" style="min-height:540px">\n        <div class="phone-bar"><span>9:41</span><div class="phone-bar-r"><i></i><i></i><i></i></div></div>\n        <div style="padding:0 6px;opacity:0.25">\n          <div style="display:flex;align-items:center;gap:4px;padding:6px 10px;background:rgba(255,255,255,.8);border-radius:16px;width:fit-content">\n            <div style="width:8px;height:8px;background:#1890ff;border-radius:50%"></div>\n            <span style="font-size:8px;color:#333">魔法学院·朝阳店</span>\n          </div>\n          <div style="height:100px;background:linear-gradient(135deg,#5B21B6,#7C3AED);border-radius:8px;margin-top:6px"></div>\n          <div style="display:flex;gap:6px;margin-top:8px">\n            <div style="flex:1;height:35px;background:#E8F4FF;border-radius:8px"></div>\n            <div style="flex:1;height:35px;background:#FFF4E8;border-radius:8px"></div>\n          </div>\n        </div>\n        <!-- 遮罩 + 白色弹窗 -->\n        <div style="position:relative;margin-top:10px">\n          <div style="position:absolute;inset:0;background:rgba(0,0,0,.5);border-radius:4px"></div>\n          <div style="position:relative;z-index:5;border:2px solid #EF4444;border-radius:14px;margin:20px 24px 0;background:#fff;overflow:hidden">\n            <span style="position:absolute;top:-8px;right:4px;background:#EF4444;color:#fff;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:600">通用弹窗</span>\n            <div style="padding:14px 18px;background:radial-gradient(circle at top left,rgba(81,220,255,.2),transparent 40%)">\n              <div style="display:flex;justify-content:center;align-items:center;margin-bottom:12px;position:relative">\n                <span style="font-size:12px;font-weight:800;color:#000">地址不一致</span>\n                <span style="position:absolute;right:0;font-size:10px;color:#999">✕</span>\n              </div>\n              <div style="font-size:8px;color:#333;text-align:center;line-height:1.6;margin-bottom:16px">您当前所在地址与【小程序地址】不一致，请手动在【界面左上角】调整。</div>\n              <div style="display:flex;justify-content:center;gap:12px">\n                <div style="padding:8px 20px;background:#f5f5f5;border-radius:8px;font-size:9px;color:#666;font-weight:700">取 消</div>\n                <div style="padding:8px 20px;background:#1890ff;border-radius:8px;font-size:9px;color:#fff;font-weight:700">自动定位</div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div></div>\n      <div class="ui-desc">\n        <h5>📍 地址不一致弹窗</h5>\n        <p>当用户与选中门店距离超过阈值时弹出，使用 <code>common-modal-box</code> 通用弹窗样式。</p>\n        <ul>\n          <li>白色圆角卡片，左上角有蓝色光晕装饰</li>\n          <li>标题「地址不一致」+ 关闭按钮</li>\n          <li>「取 消」关闭弹窗，「自动定位」重新获取 GPS</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- 无法定位弹窗 -->\n  <div class="ui-demo-row">\n    <div class="ui-demo-item">\n      <div class="phone-wireframe"><div class="phone-notch"></div><div class="phone-screen" style="min-height:540px">\n        <div class="phone-bar"><span>9:41</span><div class="phone-bar-r"><i></i><i></i><i></i></div></div>\n        <div style="padding:0 6px;opacity:0.15">\n          <div style="display:flex;align-items:center;gap:4px;padding:6px 10px;background:rgba(255,255,255,.8);border-radius:16px;width:fit-content">\n            <div style="width:8px;height:8px;background:#1890ff;border-radius:50%"></div>\n            <span style="font-size:8px;color:#333">开启定位权限</span>\n          </div>\n          <div style="height:80px;background:linear-gradient(135deg,#5B21B6,#7C3AED);border-radius:8px;margin-top:6px"></div>\n        </div>\n        <div style="position:relative;margin-top:10px">\n          <div style="position:absolute;inset:0;background:rgba(0,0,0,.5);border-radius:4px"></div>\n          <div style="position:relative;z-index:5;border:2px solid #EF4444;border-radius:14px;margin:20px 24px 0;background:#fff;overflow:hidden">\n            <div style="padding:14px 18px;background:radial-gradient(circle at top left,rgba(81,220,255,.2),transparent 40%)">\n              <div style="display:flex;justify-content:center;align-items:center;margin-bottom:12px;position:relative">\n                <span style="font-size:12px;font-weight:800;color:#000">无法定位</span>\n                <span style="position:absolute;right:0;font-size:10px;color:#999">✕</span>\n              </div>\n              <div style="font-size:8px;color:#333;text-align:center;line-height:1.6;margin-bottom:16px">当前无法获取您的地址，请开启定位或留意左上角定位是否准确</div>\n              <div style="display:flex;justify-content:center;gap:12px">\n                <div style="padding:8px 20px;background:#1890ff;border-radius:8px;font-size:9px;color:#fff;font-weight:700">获取地址</div>\n                <div style="padding:8px 20px;background:#1890ff;border-radius:8px;font-size:9px;color:#fff;font-weight:700">确 定</div>\n              </div>\n            </div>\n          </div>\n        </div>\n        <!-- 底部补齐 -->\n        <div style="padding:6px 16px;opacity:0.1">\n          <div style="height:8px;width:30%;background:rgba(255,255,255,.06);border-radius:4px"></div>\n        </div>\n      </div></div>\n      <div class="ui-desc">\n        <h5>⚠️ 无法定位弹窗</h5>\n        <p>用户未授权定位时弹出，同样是 <code>common-modal-box</code> 通用弹窗。</p>\n        <ul>\n          <li>标题「无法定位」+ 关闭按钮</li>\n          <li>「获取地址」调用 <code>wx.getLocation</code> 重新定位</li>\n          <li>「确 定」关闭弹窗，保持当前门店选择</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- 管理端权限 -->\n  <div class="ui-demo-row">\n    <div class="ui-demo-item">\n      <div class="phone-wireframe"><div class="phone-notch"></div><div class="phone-screen" style="min-height:540px">\n        <div class="phone-bar"><span>9:41</span><div class="phone-bar-r"><i></i><i></i><i></i></div></div>\n        <div style="padding:0 6px">\n          <!-- 定位栏 + 管理按钮 -->\n          <div style="position:relative">\n            <div style="display:flex;align-items:center;gap:4px;padding:6px 10px;background:rgba(255,255,255,.8);border-radius:16px;width:fit-content">\n              <div style="width:8px;height:8px;background:#1890ff;border-radius:50%"></div>\n              <span style="font-size:8px;color:#333">魔法学院·朝阳店</span>\n            </div>\n            <!-- 红框：管理按钮 -->\n            <div style="border:2px solid #EF4444;border-radius:50%;position:absolute;right:10px;top:50%;transform:translateY(-50%);padding:6px 4px;background:rgba(33,33,33,.8)">\n              <span style="position:absolute;top:-8px;right:-2px;background:#EF4444;color:#fff;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:600">管理</span>\n              <span style="font-size:8px;color:#fff">管理</span>\n            </div>\n          </div>\n          <!-- 轮播图 -->\n          <div style="height:110px;background:linear-gradient(135deg,#5B21B6,#7C3AED,#A78BFA);border-radius:8px;margin-top:6px;display:flex;align-items:center;justify-content:center;font-size:9px;color:rgba(255,255,255,.4)">Banner 轮播</div>\n          <!-- 功能卡片 -->\n          <div style="display:flex;gap:4px;margin-top:-12px;padding:0 8px">\n            <div style="flex:1;height:50px;background:#fff;border-radius:12px;box-shadow:0 2px 6px rgba(0,0,0,.05)"></div>\n            <div style="flex:1;height:50px;background:#fff;border-radius:12px;box-shadow:0 2px 6px rgba(0,0,0,.05)"></div>\n          </div>\n        </div>\n        <!-- 场次信息 -->\n        <div style="padding:6px 8px">\n          <div style="padding:10px;background:linear-gradient(155deg,rgba(110,184,253,.3),#fff 60%);border-radius:10px;margin-bottom:6px;box-shadow:0 0 8px rgba(148,215,255,.3)">\n            <div style="height:6px;width:45%;background:rgba(0,0,0,.08);border-radius:3px;margin-bottom:4px"></div>\n            <div style="height:6px;width:30%;background:rgba(0,0,0,.06);border-radius:3px;margin-bottom:4px"></div>\n            <div style="height:16px;width:30%;background:linear-gradient(90deg,#57B2FD,#3F95FF);border-radius:6px;float:right;margin-top:2px"></div>\n            <div style="clear:both"></div>\n          </div>\n        </div>\n        <!-- 底部留白 -->\n        <div style="padding:6px 12px;opacity:0.2">\n          <div style="height:40px;background:rgba(255,255,255,.06);border-radius:8px"></div>\n        </div>\n      </div></div>\n      <div class="ui-desc">\n        <h5>🛡️ 管理端权限判断</h5>\n        <p>管理员（<code>userType > 0</code>）首页右上角显示圆形「管理」按钮，点击跳转逻辑：</p>\n        <ul>\n          <li><b>中控管理员</b>（<code>userType == 3</code> 且非自定义角色）→ <code>/pages/central/central</code></li>\n          <li><b>其他管理角色</b> → <code>/pages/ticket/ticket</code></li>\n          <li><b>员工角色</b>：<code>store_staff</code> 数组中是否有当前门店的管理权限</li>\n          <li><b>超级管理员</b>：<code>super_man = true</code> 时拥有所有权限</li>\n          <li><b>功能权限</b>：通过 <code>getUserPermissions()</code> 检查具体功能权限，无权限的操作按钮隐藏或提示「无操作权限」</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n</div>';
    var div = document.createElement('div');
    div.innerHTML = html;
    var sections = div.querySelectorAll('.section-block');
    sections.forEach(function(sec) { container.appendChild(sec); });
  })();

